# Rate Limiter: Token Bucket & Sliding Window

## Implementation

```python
import threading
import time
from abc import ABC, abstractmethod
from collections import deque
from dataclasses import dataclass


class RateLimiter(ABC):
    """Common interface for rate limiting strategies."""

    @abstractmethod
    def allow(self, tokens: int = 1) -> bool:
        """Try to consume `tokens`. Return True if permitted, else False."""
        ...

    @abstractmethod
    def __enter__(self):
        ...

    @abstractmethod
    def __exit__(self, *exc):
        ...


# ---------------------------------------------------------------------------
# Token Bucket
# ---------------------------------------------------------------------------
class TokenBucketLimiter(RateLimiter):
    """
    Tokens refill continuously at `rate` per second up to `capacity`.
    Allows bursts up to `capacity`.
    """

    def __init__(self, rate: float, capacity: float):
        if rate <= 0 or capacity <= 0:
            raise ValueError("rate and capacity must be positive")
        self._rate = rate
        self._capacity = capacity
        self._tokens = capacity
        self._last = time.monotonic()
        self._lock = threading.Lock()

    def _refill(self) -> None:
        now = time.monotonic()
        elapsed = now - self._last
        if elapsed > 0:
            self._tokens = min(self._capacity, self._tokens + elapsed * self._rate)
            self._last = now

    def allow(self, tokens: int = 1) -> bool:
        if tokens <= 0:
            raise ValueError("tokens must be positive")
        with self._lock:
            self._refill()
            if self._tokens >= tokens:
                self._tokens -= tokens
                return True
            return False

    @property
    def available(self) -> float:
        with self._lock:
            self._refill()
            return self._tokens

    def __enter__(self):
        if not self.allow():
            raise RuntimeError("rate limit exceeded")
        return self

    def __exit__(self, *exc):
        return False


# ---------------------------------------------------------------------------
# Sliding Window (log-based)
# ---------------------------------------------------------------------------
class SlidingWindowLimiter(RateLimiter):
    """
    Allows at most `limit` events within any rolling `window` seconds.
    Uses a timestamp log for exact accounting.
    """

    def __init__(self, limit: int, window: float):
        if limit <= 0 or window <= 0:
            raise ValueError("limit and window must be positive")
        self._limit = limit
        self._window = window
        self._events: deque[float] = deque()
        self._lock = threading.Lock()

    def _evict(self, now: float) -> None:
        boundary = now - self._window
        while self._events and self._events[0] <= boundary:
            self._events.popleft()

    def allow(self, tokens: int = 1) -> bool:
        if tokens <= 0:
            raise ValueError("tokens must be positive")
        now = time.monotonic()
        with self._lock:
            self._evict(now)
            if len(self._events) + tokens <= self._limit:
                self._events.extend([now] * tokens)
                return True
            return False

    @property
    def available(self) -> int:
        now = time.monotonic()
        with self._lock:
            self._evict(now)
            return self._limit - len(self._events)

    def __enter__(self):
        if not self.allow():
            raise RuntimeError("rate limit exceeded")
        return self

    def __exit__(self, *exc):
        return False


# ---------------------------------------------------------------------------
# Factory
# ---------------------------------------------------------------------------
@dataclass
class RateLimitConfig:
    strategy: str          # "token_bucket" | "sliding_window"
    rate: float = 0.0      # token bucket: tokens/sec
    capacity: float = 0.0  # token bucket: max burst
    limit: int = 0         # sliding window: max events
    window: float = 0.0    # sliding window: seconds


def make_limiter(cfg: RateLimitConfig) -> RateLimiter:
    if cfg.strategy == "token_bucket":
        return TokenBucketLimiter(cfg.rate, cfg.capacity)
    if cfg.strategy == "sliding_window":
        return SlidingWindowLimiter(cfg.limit, cfg.window)
    raise ValueError(f"unknown strategy: {cfg.strategy}")
