## Tests

```python
import threading
import time
import pytest

from ratelimiter import (
    TokenBucketLimiter, SlidingWindowLimiter,
    RateLimitConfig, make_limiter,
)


# ---- Token Bucket -----------------------------------------------------------
def test_token_bucket_initial_burst():
    tb = TokenBucketLimiter(rate=1, capacity=5)
    assert all(tb.allow() for _ in range(5))   # consume full burst
    assert not tb.allow()                       # depleted


def test_token_bucket_refill():
    tb = TokenBucketLimiter(rate=10, capacity=10)
    for _ in range(10):
        assert tb.allow()
    assert not tb.allow()
    time.sleep(0.25)                            # ~2.5 tokens refilled
    assert tb.allow(2)
    assert not tb.allow(2)


def test_token_bucket_cap():
    tb = TokenBucketLimiter(rate=1000, capacity=3)
    time.sleep(0.05)                            # would refill many, capped at 3
    assert tb.available <= 3


def test_token_bucket_multi_token():
    tb = TokenBucketLimiter(rate=1, capacity=5)
    assert tb.allow(5)
    assert not tb.allow(1)


